using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        // EF Core 9 removed synchronous I/O for Cosmos — this is no longer optional.
        // All queries/saves must use async APIs (ToListAsync, SaveChangesAsync, etc.).
    }
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 8 stored "Discriminator"; EF Core 9 defaults to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries
            // reference c.Discriminator. Preserve the old name for compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id format changed.
            // EF Core 8: id = "Product|123"   EF Core 9: id = "123"
            // Existing documents use the old format. Preserve it so EF can still
            // read every existing document without a data migration.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

